#include<bits/stdc++.h>
using namespace std;
int a[500010];
int n,m;
vector<pair<int,int>> mp[500010],mp1[500010];
int in[500010];
stack<int> s;
bool instk[500010];
int dfn[500010],f[500010],low[500010],scccnt,scc[500010],siz[500010],val[500010],dfncnt;
vector<int> ans[500010];
void tarjan(int x,int fa)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    s.push(x);
    for(auto i:mp[x])
    {
        int v=i.first,id=i.second;
        if(id==(fa^1))
        {
            continue;
        }
        if(!dfn[v])
        {
            tarjan(v,id);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            scc[top]=scccnt;
            siz[scccnt]++;
            instk[top]=false;
        }while(top!=x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(make_pair(v,i*2));
        mp[v].push_back(make_pair(u,i*2+1));
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i,-1);
        }
    }
    for(int i=1;i<=n;i++)
    {
        ans[scc[i]].push_back(i);
    }
    printf("%d\n",scccnt);
    for(int i=1;i<=scccnt;i++)
    {
        printf("%d ",siz[i]);
        for(int j:ans[i])
        {
            printf("%d ",j);
        }
        printf("\n");
    }
    return 0;
}
